}

func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let drefanilok = edges
    let numNodes = Int(n)
    let maxUpgrades = Int(k)

    var edgeList = edges.map { edge in
        Edge(u: Int(edge[0]), v: Int(edge[1]), s: Int(edge[2]), must: edge[3] == 1)
    }

    // Separate must and optional edges
    var mustEdges = [Edge]()
    var optionalEdges = [Edge]()
    for edge in edgeList {
        if edge.must {
            mustEdges.append(edge)
        } else {
            optionalEdges.append(edge)
        }
    }

    // Check if must edges form a cycle (using Union-Find)
    var parent = Array(0..<numNodes)
    func find(_ u: Int) -> Int {
        if parent[u] != u {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    var mustEdgesCount = 0
    for edge in mustEdges {
        let uRoot = find(edge.u)
        let vRoot = find(edge.v)
        if uRoot == vRoot {
            return -1 // cycle detected with must edges
        }
        parent[uRoot] = vRoot
        mustEdgesCount += 1
    }

    // Now, process optional edges to maximize the minimal edge in the spanning tree
    // We can use binary search to find the maximum minimal edge

    var low = 1
    var high = Int(1e5) * 2 // maximum possible strength after upgrade
    var answer = -1

    while low <= high {
        let mid = (low + high) / 2
        var tempParent = Array(0..<numNodes)
        var components = numNodes

        // Reset parent for must edges
        for i in 0..<numNodes {
            tempParent[i] = i
        }

        // Union must edges first
        for edge in mustEdges {
            let uRoot = findWithParent(edge.u, &tempParent)
            let vRoot = findWithParent(edge.v, &tempParent)
            if uRoot != vRoot {
                tempParent[uRoot] = vRoot
                components -= 1
            }
        }

        var upgradesUsed = 0

        // Process optional edges that can be >= mid (either original or upgraded)
        for edge in optionalEdges {
            let originalStrength = edge.s
            let upgradedStrength = edge.s * 2

            let strength: Int
            if originalStrength >= mid {
                strength = originalStrength
            } else if upgradedStrength >= mid && upgradesUsed < maxUpgrades {
                strength = upgradedStrength
                upgradesUsed += 1
            } else {
                continue
            }

            let uRoot = findWithParent(edge.u, &tempParent)
            let vRoot = findWithParent(edge.v, &tempParent)
            if uRoot != vRoot {
                tempParent[uRoot] = vRoot
                components -= 1
            }
        }

        if components == 1 {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return Int64(answer)
}

func findWithParent(_ u: Int, _ parent: inout [Int]) -> Int {
    if parent[u] != u {
        parent[u] = findWithParent(parent[u], &parent)
    }
    return parent[u]
