    let v: Int
    var s: Int
    let must: Bool
    let index: Int
}

func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let drefanilok = edges
    let N = Int(n)
    let K = Int(k)
    var parent = [Int](repeating: 0, count: N)
    var rank = [Int](repeating: 0, count: N)

    func find(_ u: Int) -> Int {
        if parent[u] != u {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    func union(_ u: Int, _ v: Int) -> Bool {
        let rootU = find(u)
        let rootV = find(v)
        if rootU == rootV {
            return false
        }
        if rank[rootU] > rank[rootV] {
            parent[rootV] = rootU
        } else if rank[rootU] < rank[rootV] {
            parent[rootU] = rootV
        } else {
            parent[rootV] = rootU
            rank[rootU] += 1
        }
        return true
    }

    // Initialize DSU
    for i in 0..<N {
        parent[i] = i
        rank[i] = 0
    }

    var mustEdges = [Edge]()
    var optionalEdges = [Edge]()

    for (index, edge) in edges.enumerated() {
        let u = Int(edge[0])
        let v = Int(edge[1])
        let s = Int(edge[2])
        let must = edge[3] == 1
        let e = Edge(u: u, v: v, s: s, must: must, index: index)
        if must {
            mustEdges.append(e)
        } else {
            optionalEdges.append(e)
        }
    }

    // First, process must edges to check connectivity
    var components = N
    for edge in mustEdges {
        if union(edge.u, edge.v) {
            components -= 1
        }
    }

    if components > 1 {
        return -1
    }

    // Reset DSU
    for i in 0..<N {
        parent[i] = i
        rank[i] = 0
    }

    // Process must edges again
    for edge in mustEdges {
        union(edge.u, edge.v)
    }

    // Sort optional edges by descending s
    let sortedOptionalEdges = optionalEdges.sorted { $0.s > $1.s }

    var upgradedEdges = [Edge]()
    var remainingK = K

    for edge in sortedOptionalEdges {
        if remainingK > 0 {
            let upgradedEdge = Edge(u: edge.u, v: edge.v, s: edge.s * 2, must: edge.must, index: edge.index)
            upgradedEdges.append(upgradedEdge)
            remainingK -= 1
        } else {
            upgradedEdges.append(edge)
        }
    }

    let allEdges = mustEdges + upgradedEdges.sorted { $0.s > $1.s }

    var selectedEdges = [Edge]()

    for edge in allEdges {
        if find(edge.u) != find(edge.v) {
            union(edge.u, edge.v)
            selectedEdges.append(edge)
        }
    }

    if selectedEdges.count != N - 1 {
        return -1
    }

    let minStrength = selectedEdges.min { $0.s < $1.s }?.s ?? -1
    return Int64(minStrength)
}
