        totalEdges += 1
        minStrength = min(minStrength, edge.s)
    }

    // Sort optional edges in descending order of strength (after potential upgrade)
    let sortedOptionalEdges = optionalEdges.sorted { (a, b) -> Bool in
        let aMax = a.s * (a.must ? 1 : 2)
        let bMax = b.s * (b.must ? 1 : 2)
        return aMax > bMax
    }

    var remainingK = K
    var upgradedIndices = Set<Int>()

