        allEdges.append(Edge(u: u, v: v, s: s, must: must))
    }

    // Separate must and optional edges
    var mustEdges = allEdges.filter { $0.must }
    var optionalEdges = allEdges.filter { !$0.must }

    // Sort optional edges by s in descending order to prioritize upgrading larger edges
    optionalEdges.sort { $0.s > $1.s }

    // Apply upgrades to the top k optional edges
    let k = Int(k)
    for i in 0..<min(k, optionalEdges.count) {
        optionalEdges[i].s *= 2
        optionalEdges[i].upgraded = true
    }

    // Combine edges: must edges first, then upgraded optional edges, then non-upgraded optional edges
    var combinedEdges = mustEdges
    combinedEdges.append(contentsOf: optionalEdges.filter { $0.upgraded })
    combinedEdges.append(contentsOf: optionalEdges.filter { !$0.upgraded })

    // Krusky's algorithm to find the spanning tree with maximum minimum edge
    let m = Int(n)
    var parent = [Int](repeating: 0, count: m)
    for i in 0..<m {
        parent[i] = i
    }

    func find(_ u: Int) -> Int {
        if parent[u] != u {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    func union(_ u: Int, _ v: Int) -> Bool {
        let rootU = find(u)
        let rootV = find(v)
        if rootU == rootV {
            return false
        }
        parent[rootV] = rootU
        return true
    }

    // Sort edges in descending order of s to find the maximum minimum edge
    combinedEdges.sort { $0.s > $1.s }

    var selectedEdges = [Edge]()
    for edge in combinedEdges {
        if find(edge.u) != find(edge.v) {
            union(edge.u, edge.v)
            selectedEdges.append(edge)
            if selectedEdges.count == m - 1 {
                break
            }
        }
    }

    if selectedEdges.count != m - 1 {
        return -1
    }

    // The stability is the minimum s in the selected edges
    let stability = selectedEdges.min { $0.s < $1.s }!.s
