    foreach (e; mustEdges) {
        uf.unite(e.u, e.v);
    }

    // Check if must edges already form cycles
    if (uf.setCount != n - mustEdges.length + 1) {
        return -1;
    }

    // Sort optional edges by original strength
    optionalEdges.sort!((a, b) => a.s < b.s);

    // Binary search for the maximum possible stability
    int64 low = 1;
    int64 high = 1_000_000_000;
    int64 ans = -1;

