        int64 mid = (low + high) / 2;
        UF tempUF;
        tempUF.init(n);

        // Add must edges first
        foreach (e; mustEdges) {
            tempUF.unite(e.u, e.v);
        }

        int64 upgradesUsed = 0;

        // Try to add optional edges with s >= mid or upgraded s >= mid
        foreach (ref e; optionalEdges) {
            int64 currentS = e.s;
            if (currentS >= mid) {
                if (tempUF.unite(e.u, e.v)) {
