                if (upgradedS >= mid) {
                    if (tempUF.unite(e.u, e.v)) {
                        upgradesUsed++;
                        continue;
                    }
                }
            }
        }

        if (tempUF.setCount == 1) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
