struct UnionFind(T) {
    T[] parent;
    T[] rank;

    void init(T n) {
        parent = new T[n];
        rank = new T[n];
        foreach (i; 0..n) {
            parent[i] = i;
            rank[i] = 0;
        }
    }

    T find(T x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool unite(T x, T y) {
        x = find(x);
        y = find(y);
        if (x == y) {
            return false;
        }
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else {
            parent[y] = x;
            if (rank[x] == rank[y]) {
                rank[x]++;
            }
        }
        return true;
    }

