    int components = n.to!int;

    // Process must edges first
    foreach (e; mustEdges) {
        if (dsu.union(e.u, e.v)) {
            components--;
        }
    }

    if (components == 1) {
        // All nodes are connected by must edges, find min s among must edges
        int minS = int.max;
        foreach (e; mustEdges) {
            minS = min(minS, e.s);
        }
        return minS.to!Int64;
    }

    // Sort optional edges by s in descending order
    optionalEdges.sort!((a, b) => a.s > b.s);

    // Binary search for the maximum possible min strength
    int low = 1;
    int high = int.max;
    int result = -1;

    while (low <= high) {
        int mid = low + (high - low) / 2;

        DSU tempDsu = DSU(n.to!int);
        int tempComponents = n.to!int;

        // Union must edges first
        foreach (e; mustEdges) {
            tempDsu.union(e.u, e.v);
        }

        int usedK = 0;
        // Process optional edges with s >= mid or s * 2 >= mid if upgraded
        foreach (e; optionalEdges) {
            if (e.s >= mid) {
                if (tempDsu.union(e.u, e.v)) {
                    tempComponents--;
                }
            } else if (e.s * 2 >= mid && usedK < k.to!int) {
                if (tempDsu.union(e.u, e.v)) {
                    tempComponents--;
                    usedK++;
                }
            }
        }

        if (tempComponents == 1) {
            result = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return result.to!Int64;
}
